// ============================================================
// frontend/src/pages/Login.jsx
// Pantalla de login con diseño premium glassmorphism
// ============================================================
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [cargando, setCargando] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setCargando(true);

    // BYPASS: Simulamos medio segundo de carga
    setTimeout(() => {
      login(form.email, form.password);
      setCargando(false);
      navigate('/dashboard');
    }, 600);
  };

  return (
    <div className="login-page">
      <div className="login-card">
        {/* Logo */}
        <div className="login-card__logo">
          <div className="login-card__logo-icon">🧾</div>
          <span className="login-card__logo-text">FactuApp</span>
        </div>

        <p className="login-card__subtitle">
          Ingresa tus credenciales para acceder al sistema
        </p>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">
              Correo electrónico <span>*</span>
            </label>
            <input
              type="email"
              className="form-input"
              placeholder="admin@empresa.com"
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              required
            />
          </div>

          <div className="form-group">
            <label className="form-label">
              Contraseña <span>*</span>
            </label>
            <input
              type="password"
              className="form-input"
              placeholder="••••••••"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              required
            />
          </div>

          <button type="submit" className="btn btn--primary btn--full btn--lg" disabled={cargando}>
            {cargando ? (
              <>
                <div className="btn__spinner" />
                Iniciando sesión...
              </>
            ) : (
              'Entrar al Sistema'
            )}
          </button>
        </form>

        <div className="login-card__footer">
          <p className="login-card__footer-text">
            Sistema de Gestión de Facturación — Grupo 9 SENA
          </p>
          <div className="login-card__bypass-badge">
            ⚡ Modo de prueba activado (Bypass)
          </div>
        </div>
      </div>
    </div>
  );
}
